def _iceberg_catalog_to_nested(iceberg_catalog: IcebergCatalog) -> IcebergCatalogNested:
    """Convert flat IcebergCatalog to nested format."""
    attrs = IcebergCatalogAttributes()
    _populate_iceberg_catalog_attrs(attrs, iceberg_catalog)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        iceberg_catalog,
        _ICEBERG_CATALOG_REL_FIELDS,
        IcebergCatalogRelationshipAttributes,
    )
    return IcebergCatalogNested(
        guid=iceberg_catalog.guid,
        type_name=iceberg_catalog.type_name,
        status=iceberg_catalog.status,
        version=iceberg_catalog.version,
        create_time=iceberg_catalog.create_time,
        update_time=iceberg_catalog.update_time,
        created_by=iceberg_catalog.created_by,
        updated_by=iceberg_catalog.updated_by,
        classifications=iceberg_catalog.classifications,
        classification_names=iceberg_catalog.classification_names,
        meanings=iceberg_catalog.meanings,
        labels=iceberg_catalog.labels,
        business_attributes=iceberg_catalog.business_attributes,
        custom_attributes=iceberg_catalog.custom_attributes,
        pending_tasks=iceberg_catalog.pending_tasks,
        proxy=iceberg_catalog.proxy,
        is_incomplete=iceberg_catalog.is_incomplete,
        provenance_type=iceberg_catalog.provenance_type,
        home_id=iceberg_catalog.home_id,
        depth=iceberg_catalog.depth,
        immediate_upstream=iceberg_catalog.immediate_upstream,
        immediate_downstream=iceberg_catalog.immediate_downstream,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _iceberg_catalog_from_nested(nested: IcebergCatalogNested) -> IcebergCatalog:
    """Convert nested format to flat IcebergCatalog."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else IcebergCatalogAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _ICEBERG_CATALOG_REL_FIELDS,
        IcebergCatalogRelationshipAttributes,
    )
    return IcebergCatalog(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        depth=nested.depth,
        immediate_upstream=nested.immediate_upstream,
        immediate_downstream=nested.immediate_downstream,
        **_extract_iceberg_catalog_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _iceberg_catalog_to_nested_bytes(
    iceberg_catalog: IcebergCatalog, serde: Serde
) -> bytes:
    """Convert flat IcebergCatalog to nested JSON bytes."""
    return serde.encode(_iceberg_catalog_to_nested(iceberg_catalog))


def _iceberg_catalog_from_nested_bytes(data: bytes, serde: Serde) -> IcebergCatalog:
    """Convert nested JSON bytes to flat IcebergCatalog."""
    nested = serde.decode(data, IcebergCatalogNested)
    return _iceberg_catalog_from_nested(nested)


